import React from 'react';

const experiences = [
  {
    company: 'Meta',
    role: 'Software Engineer',
    date: 'Jul 2024 - Present',
    bullets: [
      'Placeholder: describe your team, product area, and primary technologies.',
      'Placeholder: highlight a key project or initiative you led or contributed to.',
      'Placeholder: mention cross-functional collaboration and impact metrics.',
      'Placeholder: note any tooling, infrastructure, or process improvements.',
    ],
  },
  {
    company: 'CLEAR',
    role: 'Senior Software Engineer',
    date: '2024 - Present',
    location: 'New York, NY',
    bullets: [
      'Acted as a thought leader and standardized best backend practices across hundreds of microservices, enhancing the operational efficiency and consistency of the entire engineering organization.',
      'Spearheaded the integration of Snyk to redefine security practices within the SDLC. Collaborated extensively with engineering, product, and security teams to develop and implement comprehensive training programs on vulnerability management. Established a systematic approach to address and resolve vulnerabilities prior to expiry deadlines.',
      'Partnered with multiple teams to establish Tier 1 Service Level Objectives (SLOs) and significantly enhance system observability and monitoring using Datadog, thereby improving system reliability and performance metrics.',
    ],
  },
  {
    company: 'Mark43',
    role: 'Software Engineer',
    date: '2019 - 2023',
    bullets: [
      'Collaborated across engineering, product, and QA on re-platforming the Records Management System serving law enforcement agencies nationwide.',
      'Led back-end engineering for a new Jail Management System built as a Progressive Web App using Spring Framework.',
      'Drove adoption of Keycloak as the platform\'s authentication and identity provider, taking full ownership of integration.',
      'Architected a highly customizable form system to collect variant data across diverse customer requirements.',
      'Developed and deployed high-priority fixes for mission-critical applications; organized on-site hackathons with customers.',
      'Optimized the login process enabling 46,000 users to cross-login across systems; supported TypeScript migration of the front-end codebase.',
      'Authored technical documents that decreased client deployment time by 65% and reduced thousands of unnecessary data rows from production.',
      'Led engineers through overhauling the printing subsystem and mentored multiple new hires.',
    ],
  },
  {
    company: 'Schonfeld Strategic Advisors',
    role: 'Programmer / Data Analyst',
    date: '2018 - 2019',
    bullets: [
      'Orchestrated multiple technical projects simultaneously based on evolving firm needs in a fast-paced trading environment.',
      'Automated the bi-annual reporting process for performance and risk assessment compliance analysis.',
      'Executed data science work using Python (pandas), SQL, Q/KDB+, and Excel.',
      'Modernized company data pipelines and streamlined automation for legacy systems.',
    ],
  },
  {
    company: 'Charles River Development',
    role: 'Software Engineer',
    date: '2017 - 2018',
    bullets: [
      'Developed software in Java and C# on a large codebase for an investment solutions provider managing $25T+ in assets.',
      'Built a mock testing platform that improved QA efficiency by 90%, streamlining engineer and customer workflows.',
      'Created and executed unit and automation tests; validated system enhancements, fixes, and user processes.',
    ],
  },
];

function Experience() {
  return (
    <section id="experience">
      <h2 className="section-title">Experience</h2>
      {experiences.map((exp) => (
        <div className="experience-item" key={exp.company}>
          <h3>{exp.company}</h3>
          <div className="role">{exp.role}</div>
          <div className="date">{exp.date}</div>
          <ul>
            {exp.bullets.map((b, i) => (
              <li key={i}>{b}</li>
            ))}
          </ul>
        </div>
      ))}
    </section>
  );
}

export default Experience;
